text_run.content:
sprd-audio-card,routing =
    "HPMIC Pin", "HP Nic Jack",
    "MIC Pin", "Mic Jack",
    "MIC2 Pin", "Aux Mic Jack",
    "MIC3 Pin", "Aux Mic2 Jack",
    "HeadPhone Jack", "HP Pin",
    "Ext Spk", "SPK Pin",
    "UCP1301 SPK ON", "SPK Pin",
    "Ext Spk", "UCP1301 SPK",
    "Ext Ear", "EAR Pin",
    "UCP1301 RCV ON", "EAR Pin",
    "Ext Ear", "UCP1301 RCV";

/* ucp1301 spk */
sprd-audio-card,dai-link@100 {
    ignore-suspend = <1>;
    link-name = "BE_UCPSPK";
    stream-name = "BE_ST_UCPSPK";
    no-pcm = <1>;
    dpcm-playback = <1>;
    be-id = <0>;
    dai-format = "i2s";
    plat {
        sound-dai = <&sprd_route_pcm>;
    };
    cpu {
        sound-dai = <&sprd_be_dai_lark 47>;
    };
    codec {
        sound-dai = <&ucp1301_spk 0>;
    };
};

/* ucp1301 rcv */
sprd-audio-card,dai-link@102 {
    ignore-suspend = <1>;
    link-name = "BE_UCPRCV";
    stream-name = "BE_ST_UCPRCV";
    no-pcm = <1>;
    dpcm-playback = <1>;
    be-id = <0>;
    dai-format = "i2s";
    plat {
        sound-dai = <&sprd_route_pcm>;
    };
    cpu {
        sound-dai = <&sprd_be_dai_lark 47>;
    };
    codec {
        sound-dai = <&ucp1301_rcv 0>;
    };

&i2c3 {
    #address-cells = <1>;
    #size-cells = <0>;
    status = "okay";

    ucp1301_spk: ucp1301@58 {
        compatible = "unisoc,ucp1301-spk";
        reg = <0x58>;
        reset-gpios = <&ap_gpio 148 GPIO_ACTIVE_HIGH>;
        #sound-dai-cells = <1>;
    };
};

&i2c6 {
    #address-cells = <1>;
    #size-cells = <0>;
    status = "okay";

    ucp1301_rcv: ucp1301@58 {
        compatible = "unisoc,ucp1301-rcv";
        reg = <0x58>;
        reset-gpios = <&ap_gpio 146 GPIO_ACTIVE_HIGH>;
        #sound-dai-cells = <1>;
    };
